                if (dx < 0) {
                    dx = -dx;
                    dy = -dy;
                }
                reduced = `${dx},${dy}`;
            }

            if (!lines.has(reduced)) {
                lines.set(reduced, []);
            }
            lines.get(reduced)!.push([x1, y1, x2, y2]);
        }
    }

    const trapezoids = new Set<string>();

    for (const [slope, lineSegments] of lines) {
        if (lineSegments.length < 2) {
            continue;
        }

        for (let i = 0; i < lineSegments.length; i++) {
            const [x1, y1, x2, y2] = lineSegments[i];
            for (let j = i + 1; j < lineSegments.length; j++) {
                const [x3, y3, x4, y4] = lineSegments[j];
                const pts = [`${x1},${y1}`, `${x2},${y2}`, `${x3},${y3}`, `${x4},${y4}`];
                const uniquePts = new Set(pts);
                if (uniquePts.size !== 4) {
                    continue;
                }

                let valid = true;
                for (const p of pts) {
                    if (!pointSet.has(p)) {
                        valid = false;
                        break;
                    }
                }
                if (!valid) {
                    continue;
                }

                const sortedPts = pts.sort().join('|');
                trapezoids.add(sortedPts);
            }
        }
    }

    return trapezoids.size;
}

function gcd(a: number, b: number): number {
    a = Math.abs(a);
    b = Math.abs(b);
    while (b) {
        [a, b] = [b, a % b];
    }
    return a;
}
